var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"안토노프, 당신……?","JPN":"アントノフ、あなたって……？","ENG":"Antonov, you're...","TWN":"安東諾夫，你……？"},"stage":{"bg":"EXILER_04","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"그 눈, 역시 그런건가…….","JPN":"その目、やはりそういうことなのか……","ENG":"Your eye... It is like that after all...","TWN":"那隻眼睛果然還是……"},"stage":{"bg":"EXILER_04","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"후후, 운명이라는 건 참 짓궂군.","JPN":"ふふ、運命とは実に皮肉なものだな。","ENG":"Ha ha, fate can be so cruel.","TWN":"呵呵，真是造化弄人呢。"},"stage":{"bg":"EXILER_04","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"EXILER_04","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"이정도까지 왔으면, 아무리 둔감한 자네라도 충분히 눈치챘겠지……?","JPN":"さすがにいくら鈍感な君でも、もうわかっただろう……？","ENG":"I'm sure you've noticed by now, no matter how insensitive you are.","TWN":"事情到了這個地步，就算你再遲鈍也應該有發現吧……？"},"stage":{"bg":"EXILER_04","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"내가 구태여 말하지 않았던 사실에 대해서.","JPN":"私があえて言わなかった事実について。","ENG":"Regarding the truth that I have not disclosed to you.","TWN":"我當初沒有透露的真相。"},"stage":{"bg":"EXILER_04","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"당신은…….","JPN":"あなたは……","ENG":"You're...","TWN":"你……"},"stage":{"bg":"EXILER_04","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"안토노프, 당신은 <color=#ffd34c>저</color>였군요. 다른 세계의.","JPN":"アントノフ、あなたは<color=#ffd34c>私</color>だったんですね。別の世界の。","ENG":"Antonov, you're <color=#ffd34c>me</color>, from another world.","TWN":"安東諾夫，原來你就是<color=#ffd34c>我</color>。其他世界的我。"},"stage":{"bg":"EXILER_04","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"후후…….","JPN":"ふふ……","ENG":"Ha ha...","TWN":"呵呵……"},"stage":{"bg":"EXILER_04","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"그래, 나의 이름은 <color=#ffd34c>카린</color> 안토노프.","JPN":"そうだ。私の名前は<color=#ffd34c>カリン</color>アントノフ。","ENG":"Yes, my name is <color=#ffd34c>Karin</color> Antonov.","TWN":"沒錯，我的名字是<color=#ffd34c>卡琳</color>·安東諾夫。"},"stage":{"bg":"EXILER_04","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"우리 세계의 마지막 <color=#ffd34c>델타 세븐</color>이자.","JPN":"我が世界の最後の<color=#ffd34c>デルタセブン</color>であり。","ENG":"I am our world's last member of <color=#ffd34c>Delta Seven</color>.","TWN":"我們世界最後一位<color=#ffd34c>第七三角洲部隊</color>成員。"},"stage":{"bg":"EXILER_04","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"우리 세계의 마지막 <color=#ffd34c>사명</color>을 위해.","JPN":"我が世界最後の<color=#ffd34c>使命</color>のため。","ENG":"And to fulfill our world's last <color=#ffd34c>mission</color>...","TWN":"為了我們世界最後的<color=#ffd34c>使命</color>，"},"stage":{"bg":"EXILER_04","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"마리아 안토노프 사령관님으로부터 이름과 함선을 물려받은 대원이라네.","JPN":"マリア・アントノフ司令官から、名前と艦船を引き継いだ隊員である。","ENG":"I inherited Commander Maria Antonov's name and ship.","TWN":"從瑪麗亞·安東諾夫司令官那裡，繼承了她的姓氏和艦船。"},"stage":{"bg":"EXILER_04","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"……마리아 안토노프.","JPN":"……マリア・アントノフ。","ENG":"...Maria Antonov.","TWN":"……瑪麗亞·安東諾夫。"},"stage":{"bg":"EXILER_04","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"그래서 제게 그 이름을 물어봤군요.","JPN":"だから私にその名を知っているかと聞いたんですね。","ENG":"So that's why you asked me about her name.","TWN":"所以你才問我那個名字。"},"stage":{"bg":"EXILER_04","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"그래, 내가 가장 존경하는 분이자, 내 부모 같은 분이셨어.","JPN":"そうだ、私が一番尊敬していた方であり、私の親のような存在だった。","ENG":"Yes. She is the person I respect the most, and she was also a parental figure to me.","TWN":"是的，我最尊敬的人，對我來說就像父母一樣。"},"stage":{"bg":"EXILER_04","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"그리고 이 세계의 자네 역시 존경하는 사람이 있겠지……?","JPN":"そして、この世界の君にもやはり尊敬する人物がいるだろう……？","ENG":"And I am certain you also have someone whom you respect, right...?","TWN":"這個世界的你也有尊敬的人吧……？"},"stage":{"bg":"EXILER_04","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"EXILER_04","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"나는 나의 사명을 달성하기 위해, 아주 오랜 시간 동안 차원을 항해해왔네.","JPN":"私は自分の使命を達成するために、極めて長い間次元を航海してきた。","ENG":"I have been voyaging through dimensions for ages to complete my duty.","TWN":"我為了完成我的使命，在次元中航行了很長一段時間。"},"stage":{"bg":"EXILER_04","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"그 사명을 이루기 위해…… 본의 아니게 자네의 세계를 무너트리려고도 했어…….","JPN":"その使命を果たすために……不本意ながら君の世界を崩壊させようともした……","ENG":"However, I unintentionally tried to destroy yours... just so I could fulfill my duty...","TWN":"為了實現那個使命……我甚至違背本意，打算摧毀你們的世界……"},"stage":{"bg":"EXILER_04","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"이제 와서 변명 같은 건 필요 없어요. 당신 또한 우리 세계의 해악입니다.","JPN":"今更言い訳など聞きたくありません。あなたはやはり私たちの世界の害悪です。","ENG":"Stop with the excuses. You are still harmful to our world.","TWN":"事到如今，找再多藉口也沒有用，你也是我們世界的災禍。"},"stage":{"bg":"EXILER_04","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"알고 있어.","JPN":"わかっている。","ENG":"I know.","TWN":"我知道。"},"stage":{"bg":"EXILER_04","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"하지만 그 침식체…… 아포리아는 그 사명보다 이전 문제야.","JPN":"しかしあの侵食体……アポリアはその使命以前の問題だ。","ENG":"But that C.O... Aporia is an issue that comes before any duty.","TWN":"但是那個侵蝕體……比起使命，阿波利亞才是問題。"},"stage":{"bg":"EXILER_04","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"자네도 알고 있겠지……?","JPN":"君もわかっているだろう……？","ENG":"You know as well, do you not...?","TWN":"你也知道的吧……？"},"stage":{"bg":"EXILER_04","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"알고 있을 텐데, 소령. 쐐기에 몸을 관통당했네.","JPN":"わかっているだろう、少佐。楔が身体を貫いたんだ。","ENG":"I'm sure you know why, Major. He was impaled by the Wedge.","TWN":"你應該很清楚，少校。他的身體已經被侵蝕釘穿透了。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"운 좋게 살아봤자, 급성 침식 증후군으로 인해 얼마 안 가 침식체가 되어버리겠지.","JPN":"運よく助かっても、そのうち急性侵食症候群によって侵食体になってしまうだろう。","ENG":"Even if he somehow makes it through, he'll turn into a C.O. soon due to the acute Corruption Syndrome.","TWN":"就算運氣好活下來，也會因急性侵蝕症候群，很快變成侵蝕體。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"그리고 스스로의 의지와 관계없이 사람을 죽일 걸세.","JPN":"そして自らの意思とは無関係に、人々を殺戮することになる。","ENG":"Then, he'll have no control and start killing people.","TWN":"然後，他會控制不了自己的意識開始殺害人類。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"이 세계가 끝나버리는 그 순간까지 계속.","JPN":"この世界が終わる瞬間まで、ずっとだ。","ENG":"And he won't stop until the day this world ends.","TWN":"直到這個世界徹底毀滅的那一刻為止。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"나는…… 이 세계의, 자네가 알고 있는 제이크 워커 대령님을 몰라.","JPN":"私は……この世界の、君の知っているジェイク・ウォーカー大佐を知らない。","ENG":"I... do not know the Colonel Jake Walker of this world that you do.","TWN":"我……不認識這個世界中，你認識的傑克·沃克上校。"},"stage":{"bg":"EXILER_04","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L34_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"하지만 틀림없이 인류를 위해 헌신하던 군인이었겠지……?","JPN":"しかし、きっと人類のために身を捧げた軍人だったはずだ……","ENG":"But there is no doubt that he was a soldier who contributed everything for mankind.","TWN":"但我想他一定是為人類獻身的軍人吧……？"},"stage":{"bg":"EXILER_04","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L35_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"그 분은…… 그럴 운명이니까 말이지…….","JPN":"あの方は……そういう運命だから……","ENG":"Because... that was his destiny...","TWN":"這樣……該說是命運使然嗎……"},"stage":{"bg":"EXILER_04","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L36_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"EXILER_04","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L37_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"그러니까…… 카린.","JPN":"だから……カリン。","ENG":"So... Karin.","TWN":"……卡琳。"},"stage":{"bg":"EXILER_04","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L38_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"다른 누구도 아닌, <color=#ffd34c>우리</color>의 손으로 대령님을 보내 드려야만 해.","JPN":"他の誰でもない、<color=#ffd34c>私たち</color>の手で、大佐を解放してさしあげなければならない。","ENG":"<color=#ffd34c>We</color> must be the ones who defeat Colonel.","TWN":"不是別人，<color=#ffd34c>我們</color>要親手送上校上路。"},"stage":{"bg":"EXILER_04","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L39_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"우리라고? 하지만 어떻게?","JPN":"私たち？　でもどうやって？","ENG":"Us? But how?","TWN":"我們嗎？但是要怎麼做？"},"stage":{"bg":"EXILER_04","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L40_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"어차피 함장인 내가 죽으면 아이기스와 함선의 무기고는 전부 파기돼…….","JPN":"どのみち艦長である私が死ねば、アイギスと艦船の武器庫はすべて破壊されてしまう……","ENG":"When I die, Aegis and its arsenal will all be destroyed...","TWN":"如果作為艦長的我死了，埃癸斯和武器庫裡的貯藏全都會自行銷毀。"},"stage":{"bg":"EXILER_04","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L41_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"그러니까 아이기스의 <color=#ffd34c>마스터 코드</color>를 자네에게 넘겨주지.","JPN":"だから、アイギスの<color=#ffd34c>マスターコード</color>を君に預けよう。","ENG":"But before I do, I will hand you the <color=#ffd34c>master code</color> to Aegis.","TWN":"所以，我會把埃癸斯的<color=#ffd34c>管理代碼</color>交給你。"},"stage":{"bg":"EXILER_04","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L42_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"그 대신 맹세해 줄 수 있겠나?","JPN":"その代わり、誓ってくれるか？","ENG":"Instead, I want you to promise me one thing.","TWN":"但我要你向我發誓。"},"stage":{"bg":"EXILER_04","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L43_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"<color=#ffd34c>네</color>가 <color=#ffd34c>내</color> 사명을 달성하는 거야.","JPN":"<color=#ffd34c>君</color>が<color=#ffd34c>私の</color>使命を達成すると。","ENG":"That <color=#ffd34c>you</color> will fulfill <color=#ffd34c>my</color> mission.","TWN":"<color=#ffd34c>你</color>會達成<color=#ffd34c>我</color>的使命。"},"stage":{"bg":"EXILER_04","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L44_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"대령님의 그림자를 죽이고, 이 세계의 가능성을……","JPN":"大佐のシャドウを殺して、この世界の可能性を……","ENG":"Defeat Colonel's Shadow and show this world's possibility...","TWN":"殺死上校的暗影，挽回這個世界的可能性……"},"stage":{"bg":"EXILER_04","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L45_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"이 세계가 정말로 지킬 만한 가치가 있는 세계였다는 걸…… 자네 스스로 증명해.","JPN":"この世界が本当に守る価値のある世界だったと……君自身が証明するんだ。","ENG":"Prove to yourself... that this world is worth protecting.","TWN":"就由你來證明……這個世界是否真的值得守護。"},"stage":{"bg":"EXILER_04","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L46_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"그걸로…… <color=#ffd34c>우리</color>의 사명은 완수될 테니까.","JPN":"それで……<color=#ffd34c>私たち</color>の使命は完遂される。","ENG":"That will be... how <color=#ffd34c>we</color> succeed our missions.","TWN":"這樣，就算是……完成<color=#ffd34c>我們</color>的使命了。"},"stage":{"bg":"EXILER_04","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L49_1","type":"narration","speaker":null,"text":{"KOREA":"지금은 손에 잡히지 않을 정도로 머나먼 아득한 과거.","JPN":"今は手に届かないほどの遥かな過去。","ENG":"In the distant past, well out of reach.","TWN":"現在已無法觸及的遙遠過去。"},"stage":{"bg":"BLACK","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L50_1","type":"narration","speaker":null,"text":{"KOREA":"모든 대원이 함께 했던, 그 시절의 기억.","JPN":"まだ隊員全員が生きていた、あの頃の思い出。","ENG":"A memory of when all members were together.","TWN":"所有成員一起度過的那段回憶。"},"stage":{"bg":"BLACK","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"고유 무장의 이식은 성공했다, 소령.","JPN":"固有武装の移植は成功した、少佐。","ENG":"Major, the transplant of the Unique Gear was a success.","TWN":"專屬裝備移植成功了，少校。"},"stage":{"bg":"LABORATORY_03","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"이제부터 귀관은 아이기스의 함장이자, 함선 그 자체라고 해도 과언이 아니야.","JPN":"これから貴官はアイギスの艦長であり、艦船そのものと言っても過言ではない。","ENG":"Now, it wouldn't be an exaggeration to say that you've become the captain of Aegis and also the ship itself.","TWN":"從現在開始，你就是埃癸斯的艦長了，甚至說你就是埃癸斯也不為過。"},"stage":{"bg":"LABORATORY_03","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"고유 무장에 의해 향상된 분석능력은 귀관의 정신과 아이기스 함의 시스템의 동조율을 한계까지 끌어올릴 걸세.","JPN":"固有武装によって向上した分析能力は、貴官の精神とアイギスのシステム同調率を限界まで引き上げるだろう。","ENG":"Your analytical abilities that the Unique Gear enhances will push the synchronization of the ship's system to its limits.","TWN":"藉由專屬裝備而提升的分析能力，會極大化你與埃癸斯艦系統之間的同步率。"},"stage":{"bg":"LABORATORY_03","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"한낱 프로그램 따위보다 훨씬 정교하게 함을 컨트롤 할 수 있겠지.","JPN":"プログラムに頼るよりも、遥かに精巧に艦船をコントロールできるはずだ。","ENG":"In short, you will be able to control the ship with greater precision than any program.","TWN":"比起區區的程式，更能精准地控制艦船。"},"stage":{"bg":"LABORATORY_03","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"네. 감사합니다, 부사령관님.","JPN":"はい。ありがとうございます、副司令官。","ENG":"Thank you, Deputy Commander.","TWN":"是，謝謝副司令官。"},"stage":{"bg":"LABORATORY_03","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"내게 고마워할 것 없어. 귀관은 이제 우리의 마지막 남은 희망이다.","JPN":"感謝などいらない。貴官はもはや我々に残された最後の希望なのだ。","ENG":"No need to thank me. You are now our last remaining hope.","TWN":"不需要感謝我，你是我們最後的希望了。"},"stage":{"bg":"LABORATORY_03","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"DOMINIC_DELTA_NULL_NULL","text":{"KOREA":"그러니 부디 그 눈으로 다음 번 인류의, 저물어가는 세계의 황혼을 걷어 주길 바란다.","JPN":"だからどうかその目で次の人類の、沈みゆく世界の暗闇を取り払ってやってくれ。","ENG":"I hope you use that eye for the next mankind, chasing away the twilight of their dying world.","TWN":"所以請用你的那隻眼睛，為下一批人類，為遲暮世界的黃昏拂去塵埃。"},"stage":{"bg":"LABORATORY_03","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"DOMINIC_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"하하, 어째 점점 더 사령관님을 닮아가는 것 같은데, 카린?","JPN":"はは、何だかどんどん司令官に似てきてないか、カリン？","ENG":"Hah hah! Karin, you're looking more and more like our commander now!","TWN":"哈哈，你越來越像司令官了喔，卡琳？"},"stage":{"bg":"TRAINING","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"노, 놀리지 마시라고요! 워커 대령님!","JPN":"か、からかわないでください！　ウォーカー大佐！","ENG":"S-stop teasing me, Colonel Walker!","TWN":"別，別笑我了！上校！"},"stage":{"bg":"TRAINING","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"놀리는 게 아니야. 잘 어울린다는 뜻이지.","JPN":"からかっているわけじゃない。よく似合っていると言いたいんだ。","ENG":"I'm not teasing you. I'm saying it suits you.","TWN":"沒有笑你。我的意思是很合適。"},"stage":{"bg":"TRAINING","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"처음 봤을 땐 햇병아리 같았는데, 이젠 어엿한 지휘관이 다 되었어.","JPN":"最初会った時はヒヨコにしか見えなかったが、もう立派な指揮官だ。","ENG":"You looked so clueless the day you first joined. But now, you're already a commander.","TWN":"初次見面的時候，還是個黃毛丫頭，現在已經是個稱職的指揮官了。"},"stage":{"bg":"TRAINING","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"대령님…….","JPN":"大佐……","ENG":"Colonel...","TWN":"上校……"},"stage":{"bg":"TRAINING","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"그러니까 우리 걱정은 하지 마.","JPN":"だから、俺たちの心配はするな。","ENG":"So don't worry about us.","TWN":"所以別擔心我們。"},"stage":{"bg":"TRAINING","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"네가 없더라도 우린 마지막 순간이 올 때까지 최선을 다해 싸울 테니까.","JPN":"お前がいなくても、最後の最後まで全力で戦う。","ENG":"We're going to fight until the end, even if you're not there with us.","TWN":"即使你不在，我們也會盡力戰鬥到最後一刻。"},"stage":{"bg":"TRAINING","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"MARIA_DELTA_YOUNG_NULL","text":{"KOREA":"자네 한 사람에게 너무나 큰 책무를 떠넘기는 것 같아 부끄럽군.","JPN":"君一人に大きすぎる責務を押し付けるようで恥ずかしい限りだ。","ENG":"I am ashamed to place so much responsibility on you alone.","TWN":"真是慚愧，把如此重任推給你一個人。"},"stage":{"bg":"PROLOGUE_02","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_YOUNG_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"괜찮습니다, 사령관님.","JPN":"構いません、司令官。","ENG":"It's not a problem for me, Commander.","TWN":"沒關係的，司令官。"},"stage":{"bg":"PROLOGUE_02","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_YOUNG_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"애초에 그 고유 무장의 적합자는 저 한 사람뿐이었으니까요.","JPN":"そもそも、その固有武装の適合者は私一人だけだったんですから。","ENG":"I was the only one suitable for the Unique Gear in the first place.","TWN":"因為當初能適合那個專屬裝備的人只有我。"},"stage":{"bg":"PROLOGUE_02","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_YOUNG_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"MARIA_DELTA_YOUNG_NULL","text":{"KOREA":"그건 그렇지. 하지만 앞으로 기약 없는 항해에 부하를 보내는 건 영 마음이 좋지 않아.","JPN":"そうだな。しかしこれからいつ終わるとも知れない航海に部下を行かせるのは、心が痛んでならない。","ENG":"True. But it pains me to send a subordinate on a voyage without promise.","TWN":"話雖如此。但是派遣部下去執行未來無期的航行，我的心裡非常不是滋味。"},"stage":{"bg":"PROLOGUE_02","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_YOUNG_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"MARIA_DELTA_YOUNG_NULL","text":{"KOREA":"그것도 내 딸과 같은 아이를…….","JPN":"ましてや、自分の娘のような君を……","ENG":"Even more so when she is like a daughter to me...","TWN":"況且還是對我來說如同女兒一般……"},"stage":{"bg":"PROLOGUE_02","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_YOUNG_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PROLOGUE_02","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_YOUNG_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"사령관님, 당신이 그 전쟁에서 저를 거두어 주신 순간부터.","JPN":"司令官、あなたがその戦争で私を拾って下った瞬間から。","ENG":"Commander, from the moment you took me under your wing from that war...","TWN":"司令官，當你從那場戰爭中收留我的那一刻開始。"},"stage":{"bg":"PROLOGUE_02","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_YOUNG_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"저는 지금껏 당신에게 어떻게 보답해야 할지만 생각하면서 살아왔습니다.","JPN":"私はずっと、あなたにどうしたら報いられるかばかりを考えて生きてきました。","ENG":"I have lived my entire life thinking of how I could repay you.","TWN":"我一直在思考該如何報答你。"},"stage":{"bg":"PROLOGUE_02","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_YOUNG_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"그러니, 이 임무는 제게 있어서는 오히려 영광입니다.","JPN":"ですから、この任務をいただけて、むしろ光栄と思っています。","ENG":"So to me, this mission is an honor to have.","TWN":"所以，我很榮幸能進行這項任務。"},"stage":{"bg":"PROLOGUE_02","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_YOUNG_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"사령관님이 물려주신 이 함선과 직책 그리고 이 이름을 걸고.","JPN":"司令官から引き継いだこの艦船と、肩書、そして名にかけて。","ENG":"With everything you've given me–your ship, position, and even your name.","TWN":"賭上從司令官那裡繼承的這艘艦船、職責以及姓氏。"},"stage":{"bg":"PROLOGUE_02","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_YOUNG_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"저는 반드시 사명을 완수하여, 우리 세계가 쌓아 올린 모든 것을 지켜내겠습니다!","JPN":"私は必ず使命を完遂し、私たちの世界が築き上げたすべてを守ってみせます！","ENG":"I will do everything in my power to complete my mission. I will protect what our world has built!","TWN":"我一定會完成使命，守護我們世界所積累的一切！"},"stage":{"bg":"PROLOGUE_02","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_YOUNG_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"MARIA_DELTA_YOUNG_NULL","text":{"KOREA":"괜찮아……. 카린.","JPN":"大丈夫だ……カリン。","ENG":"It's okay... Karin.","TWN":"不必如此……卡琳。"},"stage":{"bg":"PROLOGUE_02","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_YOUNG_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"MARIA_DELTA_YOUNG_NULL","text":{"KOREA":"자네 혼자 모든 걸 짊어질 필요는 없어. 자네는 자네가 할 수 있는 만큼만 하면 돼.","JPN":"ひとりで全責任を負う必要はない。君は君にできることをやればいい。","ENG":"You don't have to be responsible for everything. Just do what you are capable of.","TWN":"沒必要把責任都攬到自己身上，你只要盡己所能就好。"},"stage":{"bg":"PROLOGUE_02","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_YOUNG_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"MARIA_DELTA_YOUNG_NULL","text":{"KOREA":"나머지는……","JPN":"後は……","ENG":"And leave the rest...","TWN":"剩下的……"},"stage":{"bg":"PROLOGUE_02","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_YOUNG_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"narration","speaker":null,"text":{"KOREA":"그런건가.","JPN":"そうか。","ENG":"Is that why?","TWN":"是這樣嗎？"},"stage":{"bg":"EXILER_04","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L44_1","type":"narration","speaker":null,"text":{"KOREA":"이 세계에 사령관님이 존재하지 않았던 이유는.","JPN":"この世界に司令官が存在していない理由。","ENG":"Why you do not exist in this world, Commander...","TWN":"這個世界沒有你的原因。"},"stage":{"bg":"EXILER_04","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L45_1","type":"narration","speaker":null,"text":{"KOREA":"그리고 내가 사령관님의 이름을 물려받았던 이유는.","JPN":"そして私が司令官の名を引き継いだ理由は。","ENG":"And why your name was bestowed on me...","TWN":"還有為什麼我會繼承你的姓氏。"},"stage":{"bg":"EXILER_04","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L46_1","type":"narration","speaker":null,"text":{"KOREA":"후후, 정말이지 운명이라는 건 참 짓궂군요, 사령관님.","JPN":"ふふ、全く、運命とは実に皮肉なものですね、司令官。","ENG":"Ha ha, Fate really can be so cruel. Commander.","TWN":"呵呵，還真是……命運還真是捉弄人呢，司令官。"},"stage":{"bg":"EXILER_04","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L49_1","type":"narration","speaker":null,"text":{"KOREA":"아쉽게도 제 기나긴 항해는 여기서 종착점을 맞이합니다.","JPN":"残念ながら、私の長かった航海はここで終点を迎えます。","ENG":"I guess this is where my long voyage meets its end.","TWN":"很遺憾，我漫長的航行到這裡就結束了。"},"stage":{"bg":"BLACK","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L50_1","type":"narration","speaker":null,"text":{"KOREA":"무척이나 외롭고, 무척이나 고독한 항해였지만.","JPN":"あまりにも寂しく、あまりにも孤独な航海だったけれど。","ENG":"It was a solitary, extremely isolated journey. However...","TWN":"雖然是一次非常孤獨而且寂寞的航行。"},"stage":{"bg":"BLACK","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L1_1","type":"narration","speaker":null,"text":{"KOREA":"사령관님의 말씀대로 제가 할 수 있는 건 다 했다고 생각합니다.","JPN":"司令官のお言葉通り、自分にできることはすべてやったと思います。","ENG":"I believe I did all that I was capable of, just like you told me.","TWN":"但我已經像司令官說的那樣，盡我所能了。"},"stage":{"bg":"BLACK","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L2_1","type":"narration","speaker":null,"text":{"KOREA":"나머지는……","JPN":"後は……","ENG":"And leave the rest...","TWN":"剩下的……"},"stage":{"bg":"BLACK","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};